// SwaggerConfig.java
package com.paymentchange.customer.config;

import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.info.Contact;
import io.swagger.v3.oas.models.info.Info;
import io.swagger.v3.oas.models.info.License;
import io.swagger.v3.oas.models.servers.Server;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import java.util.List;

@Configuration
public class SwaggerConfig {

    @Bean
    public OpenAPI customOpenAPI() {
        return new OpenAPI()
            .info(new Info()
                .title("Customer Service API")
                .description("API REST para gestión de clientes en sistema financiero")
                .version("v1.0.0")
                .contact(new Contact()
                    .name("Equipo de Desarrollo")
                    .email("dev@paymentchange.com")
                    .url("https://paymentchange.com/team"))
                .license(new License()
                    .name("Apache 2.0")
                    .url("https://www.apache.org/licenses/LICENSE-2.0.html")))
            .servers(List.of(
                new Server()
                    .url("http://localhost:8081")
                    .description("Servidor de Desarrollo"),
                new Server()
                    .url("https://api.paymentchange.com")
                    .description("Servidor de Producción")
            ));
    }
}

# application.properties - Configuración Swagger
# Ruta de la especificación OpenAPI JSON
springdoc.api-docs.path=/v3/api-docs

# Ruta de Swagger UI
springdoc.swagger-ui.path=/swagger-ui.html

# Ordenar operaciones por método HTTP
springdoc.swagger-ui.operationsSorter=method

# Ordenar tags alfabéticamente
springdoc.swagger-ui.tagsSorter=alpha

# Habilitar botón Try it out por defecto
springdoc.swagger-ui.tryItOutEnabled=true

# Mostrar request duration
springdoc.swagger-ui.displayRequestDuration=true
